content:
Vue 中的 provide 和 inject 是一对用于跨层级组件通信的 API，主要用于父组件向深层嵌套的子组件传递数据，避免了通过 props 逐层传递的繁琐。
基本使用1. 父组件提供数据 (provide)&lt;script setup&gt;import &#123; provide, ref, reactive &#125; from &#x27;vue&#x27;// 提供静态数据provide(&#x27;message&#x27;, &#x27;Hello from parent&#x27;)// 提供响应式数据const count = ref(0)provide(&#x27;count&#x27;, count)// 提供对象const userInfo = reactive(&#123;  name: &#x27;John&#x27;,  age: 25&#125;)provide(&#x27;userInfo&#x27;, userInfo)// 提供方法const updateCount = (newValue) =&gt; &#123;  count.value = newValue&#125;provide(&#x27;updateCount&#x27;, updateCount)&lt;/script&gt;

2. 子组件注入数据 (inject)&lt;script setup&gt;import &#123; inject &#125; from &#x27;vue&#x27;// 注入数据const message = inject(&#x27;message&#x27;)const count = inject(&#x27;count&#x27;)const userInfo = inject(&#x27;userInfo&#x27;)const updateCount = inject(&#x27;updateCount&#x27;)// 使用默认值（如果父组件未提供）const theme = inject(&#x27;theme&#x27;, &#x27;light&#x27;) // 默认值为 &#x27;light&#x27;// 注入为只读（推荐）const readonlyCount = inject(&#x27;count&#x27;, undefined, true)// 调用父组件提供的方法const handleClick = () =&gt; &#123;  updateCount(count.value + 1)&#125;&lt;/script&gt;&lt;template&gt;  &lt;div&gt;    &lt;p&gt;&#123;&#123; message &#125;&#125;&lt;/p&gt;    &lt;p&gt;Count: &#123;&#123; count &#125;&#125;&lt;/p&gt;    &lt;button @click=&quot;handleClick&quot;&gt;增加&lt;/button&gt;  &lt;/div&gt;&lt;/template&gt;

详细示例场景：主题切换ThemeProvider.vue (顶层组件)&lt;script setup&gt;import &#123; provide, ref, computed &#125; from &#x27;vue&#x27;const theme = ref(&#x27;light&#x27;)const isDark = computed(() =&gt; theme.value === &#x27;dark&#x27;)const toggleTheme = () =&gt; &#123;  theme.value = theme.value === &#x27;light&#x27; ? &#x27;dark&#x27; : &#x27;light&#x27;&#125;// 提供主题相关数据和函数provide(&#x27;theme&#x27;, &#123;  theme,  isDark,  toggleTheme&#125;)&lt;/script&gt;&lt;template&gt;  &lt;div :class=&quot;theme&quot;&gt;    &lt;slot /&gt;  &lt;/div&gt;&lt;/template&gt;

DeepChild.vue (深层嵌套组件)&lt;script setup&gt;import &#123; inject &#125; from &#x27;vue&#x27;// 注入主题配置const themeConfig = inject(&#x27;theme&#x27;)if (!themeConfig) &#123;  throw new Error(&#x27;必须在 ThemeProvider 中使用&#x27;)&#125;&lt;/script&gt;&lt;template&gt;  &lt;button @click=&quot;themeConfig.toggleTheme&quot;&gt;    切换主题 (当前: &#123;&#123; themeConfig.theme &#125;&#125;)  &lt;/button&gt;&lt;/template&gt;

场景：国际化 (i18n)I18nProvider.vue (顶层组件)&lt;script setup&gt;import &#123; provide, ref, computed &#125; from &#x27;vue&#x27;// 语言包const messages = &#123;  en: &#123;    hello: &#x27;Hello&#x27;,    welcome: &#x27;Welcome to our application&#x27;  &#125;,  zh: &#123;    hello: &#x27;你好&#x27;,    welcome: &#x27;欢迎使用我们的应用&#x27;  &#125;&#125;const locale = ref(&#x27;zh&#x27;)const t = (key) =&gt; &#123;  return messages[locale.value][key] || key&#125;const changeLocale = (newLocale) =&gt; &#123;  locale.value = newLocale&#125;// 提供国际化相关功能provide(&#x27;i18n&#x27;, &#123;  locale,  t,  changeLocale&#125;)&lt;/script&gt;&lt;template&gt;  &lt;div&gt;    &lt;slot /&gt;  &lt;/div&gt;&lt;/template&gt;

AnyComponent.vue (任何嵌套组件)&lt;script setup&gt;import &#123; inject &#125; from &#x27;vue&#x27;const &#123; t, locale, changeLocale &#125; = inject(&#x27;i18n&#x27;)&lt;/script&gt;&lt;template&gt;  &lt;div&gt;    &lt;p&gt;&#123;&#123; t(&#x27;hello&#x27;) &#125;&#125;&lt;/p&gt;    &lt;p&gt;&#123;&#123; t(&#x27;welcome&#x27;) &#125;&#125;&lt;/p&gt;    &lt;div&gt;      &lt;button @click=&quot;changeLocale(&#x27;zh&#x27;)&quot; :disabled=&quot;locale === &#x27;zh&#x27;&quot;&gt;中文&lt;/button&gt;      &lt;button @click=&quot;changeLocale(&#x27;en&#x27;)&quot; :disabled=&quot;locale === &#x27;en&#x27;&quot;&gt;English&lt;/button&gt;    &lt;/div&gt;  &lt;/div&gt;&lt;/template&gt;

场景：用户认证状态管理AuthProvider.vue (顶层组件)&lt;script setup&gt;import &#123; provide, ref, reactive &#125; from &#x27;vue&#x27;const user = ref(null)const loading = ref(false)const login = async (username, password) =&gt; &#123;  loading.value = true  try &#123;    // 模拟 API 调用    await new Promise(resolve =&gt; setTimeout(resolve, 1000))    user.value = &#123;      id: 1,      username,      name: &#x27;John Doe&#x27;    &#125;  &#125; catch (error) &#123;    console.error(&#x27;Login failed:&#x27;, error)  &#125; finally &#123;    loading.value = false  &#125;&#125;const logout = () =&gt; &#123;  user.value = null&#125;const isAuthenticated = computed(() =&gt; !!user.value)// 提供认证相关功能provide(&#x27;auth&#x27;, &#123;  user,  loading,  isAuthenticated,  login,  logout&#125;)&lt;/script&gt;&lt;template&gt;  &lt;div&gt;    &lt;slot /&gt;  &lt;/div&gt;&lt;/template&gt;

ProtectedComponent.vue (需要认证的组件)&lt;script setup&gt;import &#123; inject &#125; from &#x27;vue&#x27;const &#123; user, isAuthenticated, login, logout &#125; = inject(&#x27;auth&#x27;)const handleLogin = () =&gt; &#123;  login(&#x27;admin&#x27;, &#x27;password&#x27;)&#125;&lt;/script&gt;&lt;template&gt;  &lt;div&gt;    &lt;template v-if=&quot;isAuthenticated&quot;&gt;      &lt;p&gt;欢迎，&#123;&#123; user.name &#125;&#125;！&lt;/p&gt;      &lt;button @click=&quot;logout&quot;&gt;退出登录&lt;/button&gt;    &lt;/template&gt;    &lt;template v-else&gt;      &lt;p&gt;请先登录&lt;/p&gt;      &lt;button @click=&quot;handleLogin&quot;&gt;登录&lt;/button&gt;    &lt;/template&gt;  &lt;/div&gt;&lt;/template&gt;

类型安全 (TypeScript)使用 TypeScript 时，可以为注入的数据定义类型：
// types/theme.tsexport interface ThemeContext &#123;  theme: &#x27;light&#x27; | &#x27;dark&#x27;  isDark: boolean  toggleTheme: () =&gt; void&#125;// 父组件import type &#123; ThemeContext &#125; from &#x27;./types/theme&#x27;import &#123; provide &#125; from &#x27;vue&#x27;provide&lt;ThemeContext&gt;(&#x27;theme&#x27;, &#123;  theme: &#x27;light&#x27;,  isDark: false,  toggleTheme: () =&gt; &#123; /* ... */ &#125;&#125;)// 子组件import &#123; inject &#125; from &#x27;vue&#x27;import type &#123; ThemeContext &#125; from &#x27;./types/theme&#x27;const themeContext = inject&lt;ThemeContext&gt;(&#x27;theme&#x27;)

最佳实践1. 使用 Symbol 作为 key避免命名冲突：
// keys.jsexport const THEME_KEY = Symbol(&#x27;theme&#x27;)export const USER_KEY = Symbol(&#x27;user&#x27;)// 父组件import &#123; THEME_KEY &#125; from &#x27;./keys&#x27;provide(THEME_KEY, themeData)// 子组件import &#123; THEME_KEY &#125; from &#x27;./keys&#x27;const themeData = inject(THEME_KEY)

2. 提供响应式数据import &#123; computed, provide, reactive &#125; from &#x27;vue&#x27;const user = reactive(&#123; name: &#x27;John&#x27;, age: 25 &#125;)const isAdult = computed(() =&gt; user.age &gt;= 18)provide(&#x27;user&#x27;, &#123;  user,  isAdult&#125;)

3. 设置默认值和验证// 注入时设置默认值const injectedValue = inject(&#x27;key&#x27;, &#x27;default value&#x27;)// 或者使用工厂函数const value = inject(&#x27;key&#x27;, () =&gt; createDefaultValue(), true)

4. 避免直接修改注入的值// ❌ 不推荐：直接修改const user = inject(&#x27;user&#x27;)user.name = &#x27;New Name&#x27;// ✅ 推荐：通过父组件提供的方法修改const updateUser = inject(&#x27;updateUser&#x27;)updateUser(&#123; name: &#x27;New Name&#x27; &#125;)

注意事项provide 和 inject 不是响应式的
默认情况下，注入的值不是响应式的
如果需要响应式，应该提供 ref 或 reactive 对象
只能在 setup() 或  中使用

避免过度使用
简单的父子通信使用 props/emits
复杂的状态管理考虑使用 Pinia

注入依赖的可选性// 如果依赖是必需的const requiredValue = inject(&#x27;requiredKey&#x27;)if (!requiredValue) &#123;  throw new Error(&#x27;requiredKey 必须被提供&#x27;)&#125;

适用场景这种模式特别适合：

全局配置（主题、语言等）
共享工具函数
复杂的表单组件
组件库开发

高级用法和技巧1. 组合多个 Provider可以创建多个 Provider 来管理不同领域的状态：
&lt;!-- App.vue --&gt;&lt;template&gt;  &lt;ThemeProvider&gt;    &lt;I18nProvider&gt;      &lt;AuthProvider&gt;        &lt;RouterView /&gt;      &lt;/AuthProvider&gt;    &lt;/I18nProvider&gt;  &lt;/ThemeProvider&gt;&lt;/template&gt;

2. 使用 provide/inject 与 Composition API 结合创建可复用的 composable 函数：
// composables/useTheme.jsimport &#123; inject &#125; from &#x27;vue&#x27;export function useTheme() &#123;  const themeConfig = inject(&#x27;theme&#x27;)    if (!themeConfig) &#123;    throw new Error(&#x27;useTheme must be used within a ThemeProvider&#x27;)  &#125;    return themeConfig&#125;// 在组件中使用import &#123; useTheme &#125; from &#x27;@/composables/useTheme&#x27;const &#123; theme, toggleTheme &#125; = useTheme()

3. 动态注入值可以根据条件动态提供不同的值：
&lt;script setup&gt;import &#123; provide, ref, computed &#125; from &#x27;vue&#x27;const userRole = ref(&#x27;guest&#x27;) // 可以从认证状态获取const permissions = computed(() =&gt; &#123;  if (userRole.value === &#x27;admin&#x27;) &#123;    return [&#x27;read&#x27;, &#x27;write&#x27;, &#x27;delete&#x27;]  &#125; else if (userRole.value === &#x27;user&#x27;) &#123;    return [&#x27;read&#x27;, &#x27;write&#x27;]  &#125;  return [&#x27;read&#x27;]&#125;)provide(&#x27;permissions&#x27;, permissions)&lt;/script&gt;

4. 与 Pinia/Vuex 集成在大型应用中，可以结合 Pinia 或 Vuex 使用：
&lt;script setup&gt;import &#123; provide &#125; from &#x27;vue&#x27;import &#123; useUserStore &#125; from &#x27;@/stores/user&#x27;const userStore = useUserStore()// 提供 store 的部分功能provide(&#x27;user&#x27;, &#123;  user: computed(() =&gt; userStore.user),  login: userStore.login,  logout: userStore.logout&#125;)&lt;/script&gt;

5. 测试策略在测试中，可以轻松模拟 provide 的值：
// 测试文件import &#123; mount &#125; from &#x27;@vue/test-utils&#x27;import MyComponent from &#x27;@/components/MyComponent.vue&#x27;test(&#x27;should use injected theme&#x27;, () =&gt; &#123;  const wrapper = mount(MyComponent, &#123;    global: &#123;      provide: &#123;        theme: &#123;          theme: &#x27;light&#x27;,          isDark: false,          toggleTheme: vi.fn()        &#125;      &#125;    &#125;  &#125;)    expect(wrapper.text()).toContain(&#x27;当前主题: light&#x27;)&#125;)

6. 类型推断增强使用 TypeScript 时，可以创建类型工具来增强类型推断：
// types/inject.tsexport function createInjectionKey&lt;T&gt;(key: string) &#123;  return Symbol(key) as InjectionKey&lt;T&gt;&#125;// 使用export const THEME_KEY = createInjectionKey&lt;ThemeContext&gt;(&#x27;theme&#x27;)// 父组件provide(THEME_KEY, themeContext)// 子组件const themeContext = inject(THEME_KEY) // 类型自动推断为 ThemeContext | undefined

性能优化建议1. 避免在 provide 中传递复杂的计算值对于复杂的计算，应该使用 computed 来缓存结果：
// ❌ 不推荐：每次组件渲染都会重新计算provide(&#x27;expensiveValue&#x27;, &#123;  data: heavyComputation() // 每次都会重新执行&#125;)// ✅ 推荐：使用 computed 缓存计算结果import &#123; computed &#125; from &#x27;vue&#x27;const expensiveValue = computed(() =&gt; heavyComputation())provide(&#x27;expensiveValue&#x27;, expensiveValue)

2. 合理使用响应式对象
对于不需要响应式的数据，直接提供原始值
对于需要响应式的数据，使用 ref 或 reactive
对于大型对象，考虑使用 shallowReactive 来减少响应式开销

// 不需要响应式的数据provide(&#x27;API_BASE_URL&#x27;, &#x27;https://api.example.com&#x27;)// 需要响应式的数据provide(&#x27;user&#x27;, reactive(&#123; name: &#x27;John&#x27; &#125;))// 大型对象使用 shallowReactiveimport &#123; shallowReactive &#125; from &#x27;vue&#x27;provide(&#x27;largeConfig&#x27;, shallowReactive(largeConfigObject))

3. 避免过度使用 provide/inject
对于简单的父子通信，使用 props/emits 更高效
对于跨多个层级的通信，才考虑使用 provide/inject
对于全局状态管理，大型应用考虑使用 Pinia

4. 注意组件卸载时的清理如果提供的是需要清理的资源（如定时器、事件监听器），应该在组件卸载时清理：
&lt;script setup&gt;import &#123; provide, onUnmounted &#125; from &#x27;vue&#x27;const intervalId = setInterval(() =&gt; &#123;  console.log(&#x27;Tick&#x27;)&#125;, 1000)provide(&#x27;intervalId&#x27;, intervalId)onUnmounted(() =&gt; &#123;  clearInterval(intervalId)&#125;)&lt;/script&gt;

5. 使用 Symbol 作为 key 的性能考虑使用 Symbol 作为 key 可以避免命名冲突，但会增加少量内存开销。对于全局配置，这种开销是可以接受的：
// keys.jsexport const THEME_KEY = Symbol(&#x27;theme&#x27;)export const USER_KEY = Symbol(&#x27;user&#x27;)

6. 按需注入只注入组件实际需要的值，避免注入整个对象：
// ❌ 不推荐：注入整个对象const themeConfig = inject(&#x27;theme&#x27;)const &#123; toggleTheme &#125; = themeConfig// ✅ 推荐：直接注入需要的方法const toggleTheme = inject(&#x27;toggleTheme&#x27;)
